fig = uifigure('Name', 'Dobot Magician Lite', 'Position', [100 100 700 600]); %[output:779f6819]
ax = uiaxes(fig, "Position", [10 250 450 350]); %[output:779f6819]
title(ax, "Joint Positions"); %[output:779f6819]
xlabel(ax, 'X'); %[output:779f6819]
ylabel(ax, 'Y'); %[output:779f6819]
zlabel(ax, 'Z'); %[output:779f6819]
lim = [-0.3 0.3];
ax.XLim = lim; %[output:779f6819]
ax.YLim = lim; %[output:779f6819]
ax.ZLim = lim; %[output:779f6819]


origin = plot3(ax, 0, 0, 0, 'bo', MarkerFaceColor='b'); %[output:779f6819]
hold(ax, 'on'); %[output:779f6819]
joint2 = plot3(ax, 0.1, 0.1, 0.1, 'go', MarkerFaceColor='g'); %[output:779f6819]
end_effector = plot3(ax, 0.2, 0.2, 0, 'ro', MarkerFaceColor='r'); %[output:779f6819]
link2 = plot3(ax, [0 0], [0 0], [0 0], 'm-', LineWidth=3); %[output:779f6819]
link3 = plot3(ax, [0 0], [0 0], [0 0], 'm-', LineWidth=3); %[output:779f6819]
hold(ax, 'on'); %[output:779f6819]
grid(ax, 'on'); %[output:779f6819]
grid(ax, 'minor'); %[output:779f6819]

panel = uipanel(fig, Position=[0 0 500 200]); %[output:779f6819]
grd = uigridlayout(panel, [4 2]); %[output:779f6819]
grd.ColumnWidth = {20, '1x'}; %[output:779f6819]

theta1Label = uilabel(grd); %[output:779f6819]
theta1Label.Interpreter = 'latex'; %[output:779f6819]
theta1Label.Text = '$\theta_1'; %[output:779f6819]

theta1 = uislider(grd); %[output:779f6819]
theta1.Limits = [-175 175]; %[output:779f6819]

theta2Label = uilabel(grd); %[output:779f6819]
theta2Label.Interpreter = 'latex'; %[output:779f6819]
theta2Label.Text = '$\theta_2'; %[output:779f6819]
theta2 = uislider(grd); %[output:779f6819]
theta2.Limits = [-175 175]; %[output:779f6819]


theta3Label = uilabel(grd); %[output:779f6819]
theta3Label.Interpreter = 'latex'; %[output:779f6819]
theta3Label.Text = '$\theta_3'; %[output:779f6819]
theta3 = uislider(grd); %[output:779f6819]
theta3.Limits = [-175 175]; %[output:779f6819]

theta4Label = uilabel(grd); %[output:779f6819]
theta4Label.Interpreter = 'latex'; %[output:779f6819]
theta4Label.Text = '$\theta_4'; %[output:779f6819]
theta4 = uislider(grd); %[output:779f6819]
theta4.Limits = [-175 175]; %[output:779f6819]

thetas = [theta1 theta2 theta3 theta4] %[output:38172097]

valueChanged = @() updatePlots(origin, joint2, end_effector, link2, link3, thetas);

theta1.ValueChangedFcn = @(src, event) valueChanged(); %[output:779f6819]
theta2.ValueChangedFcn = @(src, event) valueChanged(); %[output:779f6819]
theta3.ValueChangedFcn = @(src, event) valueChanged(); %[output:779f6819]
theta4.ValueChangedFcn = @(src, event) valueChanged(); %[output:779f6819]

valueChanged(); %[output:779f6819]


function updatePlots(origin, joint2, end_effector, link2, link3, thetas)
    th1 = deg2rad(thetas(1).Value);
    th2 = deg2rad(thetas(2).Value);
    th3 = deg2rad(thetas(3).Value);
    th4 = deg2rad(thetas(4).Value);
    [T04, T02] = dml(th1, th2, th3, th4);

    joint2.XData = T02(1,4);
    joint2.YData = T02(2,4);
    joint2.ZData = T02(3,4);

    end_effector.XData = T04(1,4);
    end_effector.YData = T04(2,4);
    end_effector.ZData = T04(3,4);

    link2.XData = [origin.XData joint2.XData];
    link2.YData = [origin.YData joint2.YData];
    link2.ZData = [origin.ZData joint2.ZData];

    link3.XData = [joint2.XData end_effector.XData];
    link3.YData = [joint2.YData end_effector.YData];
    link3.ZData = [joint2.ZData end_effector.ZData];
end


